fn shutdown_status(pool_id: felt252) -> felt252 {
    let inferred = infer_shutdown_mode_from_timestamp(pool_id);
    if inferred != SHUTDOWN_MODE_NONE {
        return inferred;
    }
    let fixed_shutdown_mode = self.fixed_shutdown_mode.read(pool_id);
    if fixed_shutdown_mode != SHUTDOWN_MODE_NONE {
        return fixed_shutdown_mode;
    }
    SHUTDOWN_MODE_NONE
}

